transform_js:
var target = rawData.target;
var cusum = 0;
transformedData = rawData.rows.map(function(r) { cusum += (r.v - target); return [r.n, cusum]; });

echarts_js:
option = {
  title: { text: 'CUSUM Control Chart', left: 'center' },
  tooltip: { trigger: 'axis' },
  xAxis: { type: 'value', name: 'Sample #' },
  yAxis: { type: 'value', name: 'Cumulative Sum' },
  series: [{
    type: 'line',
    data: transformedData,
    smooth: false,
    lineStyle: { width: 2, color: '#5470c6' },
    markLine: { data: [{ yAxis: 0, lineStyle: { color: '#999', type: 'dashed' } }] }
  }]
};
